class Solution {
    fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
        // Sort edges by time in ascending order
        edges.sortBy { it[2] }

        // Initialize Union-Find data structure
        val uf = UnionFind(n.toInt())

        // Keep track of the number of connected components
        var components = n.toInt()

        // Iterate through edges in order of increasing time
        for (edge in edges) {
            val u = edge[0].toInt()
            val v = edge[1].toInt()
            val time = edge[2]

            // If the nodes are in different sets, we merge them
            if (uf.find(u) != uf.find(v)) {
                uf.union(u, v)
                components--
            }

            // Check if we have achieved at least k components
            if (components >= k.toInt()) {
                return time
            }
        }

        // If we haven't found a time yet, return the time of the last edge (all edges are removed)
        return edges[edges.lastIndex][2]
    }
}

class UnionFind(val size: Int) {
    val parent = IntArray(size)
    val rank = IntArray(size)

    init {
        for (i in 0 until size) {
            parent[i] = i
            rank[i] = 0
        }
    }

    fun find(x: Int): Int {
        if (parent[x] != x) {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    fun union(x: Int, y: Int) {
        val xRoot = find(x)
        val yRoot = find(y)

        if (xRoot == yRoot) return

        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot
        } else {
            parent[yRoot] = xRoot
            if (rank[xRoot] == rank[yRoot]) {
                rank[xRoot]++
            }
        }
    }
}
